import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

export default function CustomerDashboard() {

  const user = JSON.parse(localStorage.getItem("user"));

  const [requests, setRequests] = useState([]);
  const [workers, setWorkers] = useState([]);

  const [form, setForm] = useState({
    workType: "",
    labourId: "",
    labourName: "",
    location: "",
    date: ""
  });

  const jobs = [
    "Electrician",
    "Plumber",
    "Painter",
    "Carpenter",
    "Cleaner",
    "Technician",
    "Welder",
    "Driver"
  ];

  useEffect(() => {
    getRequests();
  }, []);

  const getRequests = async () => {
    try {
      const res = await axios.get(
        `http://localhost:5000/api/request/customer/${user.name}`
      );
      setRequests(res.data);
    } catch (err) {
      console.log(err);
    }
  };

  const searchWorkers = async (workType) => {
    try {
      const res = await axios.get(
        "http://localhost:5000/api/auth/workers"
      );

      const filtered = res.data.filter((worker) =>
        worker.skills.includes(workType)
      );

      setWorkers(filtered);
    } catch (err) {
      console.log(err);
    }
  };

  const sendRequest = async () => {
    try {
      await axios.post(
        "http://localhost:5000/api/request/send",
        {
          customerName: user.name,
          customerId: user._id,
          labourId: form.labourId,
          labourName: form.labourName,
          workType: form.workType,
          location: form.location,
          date: form.date,
          timings: ["9AM - 12PM"]
        }
      );

      alert("Request Sent Successfully");

      setForm({
        workType: "",
        labourId: "",
        labourName: "",
        location: "",
        date: ""
      });

      setWorkers([]);
      getRequests();
    } catch (err) {
      console.log(err);
    }
  };

  const submitFeedback = async (id, rating, comment) => {
    if (!rating || !comment) {
      return alert("Please give rating and review");
    }

    try {
      await axios.put(
        `http://localhost:5000/api/request/feedback/${id}`,
        {
          rating: Number(rating),
          comment
        }
      );

      alert("Feedback Submitted");
      getRequests();
    } catch (err) {
      console.log(err);
    }
  };

  return (
    <div style={styles.page}>
      <Navbar />

      <div style={styles.container}>

        {/* LEFT FORM */}
        <div style={styles.leftCard}>
          <h2>Hire Workers</h2>

          <select
            style={styles.input}
            value={form.workType}
            onChange={(e) => {
              setForm({ ...form, workType: e.target.value });
              searchWorkers(e.target.value);
            }}
          >
            <option value="">Select Work</option>
            {jobs.map((job, i) => (
              <option key={i} value={job}>{job}</option>
            ))}
          </select>

          {workers.length > 0 && (
            <select
              style={styles.input}
              onChange={(e) => {
                const worker = workers.find(
                  (w) => w._id === e.target.value
                );

                setForm({
                  ...form,
                  labourId: worker._id,
                  labourName: worker.name
                });
              }}
            >
              <option>Select Worker</option>
              {workers.map((w) => (
                <option key={w._id} value={w._id}>
                  {w.name} - {w.city}
                </option>
              ))}
            </select>
          )}

          <input
            style={styles.input}
            placeholder="Location"
            onChange={(e) =>
              setForm({ ...form, location: e.target.value })
            }
          />

          <input
            type="date"
            style={styles.input}
            onChange={(e) =>
              setForm({ ...form, date: e.target.value })
            }
          />

          <button style={styles.button} onClick={sendRequest}>
            Send Request
          </button>
        </div>

        {/* RIGHT REQUESTS */}
        <div style={styles.rightCard}>
          <h2>My Requests</h2>

          {requests.map((req) => (
            <div key={req._id} style={styles.card}>

              <h3>{req.labourName}</h3>

              <p>Work: {req.workType}</p>
              <p>Location: {req.location}</p>
              <p>Status: {req.status}</p>

              {/* ⭐ STAR RATING UI */}
              {req.customerDecision === "Accepted" && (
                <div style={styles.feedbackBox}>

                  <div style={styles.starRow}>
                    {[1, 2, 3, 4, 5].map((star) => (
                      <span
                        key={star}
                        style={{
                          ...styles.star,
                          color:
                            (req.tempRating || 0) >= star
                              ? "#facc15"
                              : "#374151"
                        }}
                        onClick={() =>
                          setRequests(
                            requests.map((item) =>
                              item._id === req._id
                                ? { ...item, tempRating: star }
                                : item
                            )
                          )
                        }
                      >
                        ★
                      </span>
                    ))}
                  </div>

                  <textarea
                    placeholder="Write review..."
                    style={styles.textarea}
                    value={req.tempComment || ""}
                    onChange={(e) =>
                      setRequests(
                        requests.map((item) =>
                          item._id === req._id
                            ? { ...item, tempComment: e.target.value }
                            : item
                        )
                      )
                    }
                  />

                  <button
                    style={styles.button}
                    onClick={() =>
                      submitFeedback(
                        req._id,
                        req.tempRating,
                        req.tempComment
                      )
                    }
                  >
                    Submit Rating
                  </button>

                </div>
              )}

              {/* SHOW SAVED FEEDBACK */}
              {req.feedback && (
                <div style={styles.savedFeedback}>
                  ⭐ {req.feedback.rating}/5
                  <p>{req.feedback.comment}</p>
                </div>
              )}

            </div>
          ))}
        </div>

      </div>
    </div>
  );
}

/* ================= STYLES ================= */

const styles = {

  page: {
    background: "#0b0f19",
    minHeight: "100vh",
    color: "white"
  },

  container: {
    display: "grid",
    gridTemplateColumns: "1fr 1fr",
    gap: "20px",
    padding: "20px"
  },

  leftCard: {
    background: "#111827",
    padding: "20px",
    borderRadius: "12px",
    border: "1px solid #f97316"
  },

  rightCard: {
    background: "#111827",
    padding: "20px",
    borderRadius: "12px",
    border: "1px solid #f97316"
  },

  card: {
    padding: "15px",
    border: "1px solid #374151",
    borderRadius: "10px",
    marginBottom: "12px"
  },

  input: {
    width: "100%",
    padding: "10px",
    marginBottom: "10px",
    borderRadius: "8px",
    border: "1px solid #374151",
    background: "#0f172a",
    color: "white"
  },

  button: {
    width: "100%",
    padding: "10px",
    background: "#f97316",
    border: "none",
    borderRadius: "8px",
    color: "white",
    cursor: "pointer"
  },

  starRow: {
    display: "flex",
    gap: "5px",
    marginBottom: "10px"
  },

  star: {
    fontSize: "22px",
    cursor: "pointer"
  },

  textarea: {
    width: "100%",
    height: "70px",
    marginBottom: "10px",
    borderRadius: "8px",
    border: "1px solid #374151",
    background: "#0f172a",
    color: "white",
    padding: "10px"
  },

  feedbackBox: {
    marginTop: "10px"
  },

  savedFeedback: {
    marginTop: "10px",
    padding: "10px",
    borderRadius: "8px",
    background: "#0f172a"
  }
};
